import json

# Read the result from the first batch
batch1_result = locals()['var_functions.query_db:38']
print(f"First batch results: {len(batch1_result)} stocks")

# Filter stocks with more up days than down days
stocks_with_more_up = []
for stock in batch1_result:
    if stock['up_days'] != 'nan' and stock['down_days'] != 'nan':
        up = float(stock['up_days'])
        down = float(stock['down_days'])
        if up > down:
            stocks_with_more_up.append({
                'symbol': stock['symbol'],
                'up_days': up,
                'down_days': down,
                'net_advantage': up - down
            })

print(f"Stocks with more up days in batch 1: {len(stocks_with_more_up)}")
for stock in sorted(stocks_with_more_up, key=lambda x: x['net_advantage'], reverse=True):
    print(f"  {stock['symbol']}: {stock['up_days']:.0f} up, {stock['down_days']:.0f} down (net: +{stock['net_advantage']:.0f})")

result = {
    'batch1_up_stocks': len(stocks_with_more_up),
    'top_from_batch1': sorted(stocks_with_more_up, key=lambda x: x['net_advantage'], reverse=True)[:3]
}
print('__RESULT__:')
print(json.dumps(result))

